-- 2) Grays: uniform "System Gray NN", value-sorted (notation breaks ties).
UPDATE "public"."lab_grays" lg
   SET "color_name" = sub.nm
  FROM (
    SELECT "id", 'System Gray ' || LPAD(
             ROW_NUMBER() OVER (ORDER BY "value", "notation")::text, 2, '0'
           ) AS nm FROM "public"."lab_grays"
  ) sub
 WHERE lg."id" = sub."id";

-- 3) Enforce the per-chip-name invariant now that every row is backfilled.
ALTER TABLE "public"."lab_munsell" ALTER COLUMN "color_name" SET NOT NULL;
ALTER TABLE "public"."lab_grays"   ALTER COLUMN "color_name" SET NOT NULL;

-- 4) Old per-trace palette indices reference the previous mapping → drop them.
--    The UI shows a 'Re-run this trace' state for NULL (mobile-colors-sheet).
UPDATE "public"."project_image_trace" SET "palette_indices_used" = NULL;

-- 5) Retire the ISCC-NBS bucket naming: drop the column (both tables) + the function.
ALTER TABLE "public"."lab_munsell" DROP COLUMN IF EXISTS "iscc_nbs_name";
ALTER TABLE "public"."lab_grays"   DROP COLUMN IF EXISTS "iscc_nbs_name";
DROP FUNCTION IF EXISTS "public"."derive_iscc_nbs_name"(text, numeric, numeric, numeric);

-- 6) Refresh comments that named the dropped function.
COMMENT ON COLUMN "public"."lab_munsell"."hue_pct" IS 'consumed by the build-time palette generator (color-lab); not read by app code';
COMMENT ON COLUMN "public"."lab_munsell"."hue_family" IS 'consumed by the build-time palette generator (color-lab); not read by app code';
COMMENT ON COLUMN "public"."lab_munsell"."value" IS 'consumed by the build-time palette generator (color-lab); not read by app code';
COMMENT ON COLUMN "public"."lab_munsell"."chroma" IS 'consumed by the build-time palette generator (color-lab); not read by app code';
COMMENT ON TABLE "public"."lab_munsell" IS '512-chip tier palette: perceptually-even OKLab farthest-point over the in-gamut Munsell pool, denser in the specialized regions (skin/nature/sky/sea), JND-floored + chroma-floored (no overlap with lab_grays). palette_index = selection rank 0..511; tiers 128/256/512 are strict prefixes, active tier gated app-side by PALETTE_TIER. color_name = unique display name.';
